// ByKeyword returns the tag for a DICOM keyword.
func ByKeyword(keyword string) (Tag, bool) {
	tag, ok := keywordToTag[keyword]
	return tag, ok
}

// Keyword returns the DICOM keyword for a tag.
func Keyword(t Tag) (string, bool) {
	keyword, ok := tagToKeyword[t]
	return keyword, ok
}
